import { HttpError } from 'wasp/server'

export const createTask = async ({ description }: { description: string }, context: any) => {
  if (!context.user) {
    throw new HttpError(401)
  }
  return context.entities.Task.create({
    data: {
      description,
      isDone: false,
      user: { connect: { id: context.user.id } }
    }
  })
}

export const updateTask = async ({ id, isDone }: { id: number, isDone: boolean }, context: any) => {
  if (!context.user) {
    throw new HttpError(401)
  }

  const task = await context.entities.Task.findUnique({ where: { id } })
  if (!task || task.userId !== context.user.id) {
    throw new HttpError(403)
  }

  return context.entities.Task.update({
    where: { id },
    data: { isDone }
  })
}

