import { useQuery, useAction, getTasks, createTask, updateTask } from 'wasp/client/operations'
import { logout } from 'wasp/client/auth'
import { useState } from 'react'

export const MainPage = () => {
  const { data: tasks, isLoading, error } = useQuery(getTasks)
  const createTaskFn = useAction(createTask)
  const updateTaskFn = useAction(updateTask)
  const [description, setDescription] = useState('')

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!description.trim()) return
    try {
      await createTaskFn({ description })
      setDescription('')
    } catch (err) {
      console.error(err)
    }
  }

  const handleToggle = async (id: number, isDone: boolean) => {
    try {
      await updateTaskFn({ id, isDone: !isDone })
    } catch (err) {
      console.error(err)
    }
  }

  return (
    <div style={{ padding: '20px' }}>
      <h1>Todo List</h1>
      <button onClick={logout}>Logout</button>

      <form onSubmit={handleSubmit} style={{ marginTop: '20px', marginBottom: '20px' }}>
        <input 
          type="text" 
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          placeholder="New task..."
        />
        <button type="submit">Add Task</button>
      </form>

      {isLoading && <div>Loading...</div>}
      {error && <div>Error: {error.message}</div>}

      {tasks && tasks.length === 0 && <div>No tasks yet.</div>}

      {tasks && (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {tasks.map((task: any) => (
            <li key={task.id} style={{ marginBottom: '10px' }}>
              <label>
                <input 
                  type="checkbox" 
                  checked={task.isDone}
                  onChange={() => handleToggle(task.id, task.isDone)}
                />
                <span style={{ marginLeft: '10px', textDecoration: task.isDone ? 'line-through' : 'none' }}>
                  {task.description}
                </span>
              </label>
            </li>
          ))}
        </ul>
      )}
    </div>
  )
}

